query:
SELECT p.id, p.companyName, p.addressCountry, p.billingCountry 
FROM partners p 
WHERE p.id IN (
  SELECT partnerId FROM orders WHERE orderNumber IN ('CMD-202603-0001', 'CMD-TEST-001', 'CMD-TEST-002')
);

